import { useState, useCallback, useRef } from 'react';
import { motion, AnimatePresence, useMotionValue, useTransform, useAnimation } from 'framer-motion';

// ─── Design Tokens (inline for self-contained component) ─────────────────────
const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  surface2: '#111A24',
  border: '#1F2A37',
  textPrimary: '#E5E7DB',
  textSecondary: '#90A3AF',
  green: '#22C55E',
  red: '#EF4444',
  blue: '#60A5FA',
  amber: '#F59E0B',
  purple: '#A78BFA',
};
const mono = "'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, monospace";
const body = "'Plus Jakarta Sans', Inter, system-ui, sans-serif";

// ─── Accent stripe gradient for top edge ─────────────────────────────────────
function accentGradient(color) {
  if (color === 'green' || color === C.green) return `linear-gradient(90deg, ${C.green}, #36BDF0)`;
  if (color === 'red' || color === C.red) return `linear-gradient(90deg, ${C.red}, #FB7185)`;
  if (color === 'blue' || color === C.blue) return `linear-gradient(90deg, ${C.blue}, ${C.purple})`;
  if (color === 'amber' || color === C.amber) return `linear-gradient(90deg, ${C.amber}, #FBBF24)`;
  if (color === 'purple' || color === C.purple) return `linear-gradient(90deg, ${C.purple}, #C084FC)`;
  return `linear-gradient(90deg, ${C.blue}, ${C.purple})`;
}

// ─── Chevron icon ────────────────────────────────────────────────────────────
function Chevron({ open }) {
  return (
    <motion.svg
      width={16}
      height={16}
      viewBox="0 0 16 16"
      fill="none"
      animate={{ rotate: open ? 180 : 0 }}
      transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
      style={{ flexShrink: 0 }}
    >
      <path
        d="M4 6L8 10L12 6"
        stroke={C.textSecondary}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </motion.svg>
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// ExpandableCard — Base reusable card with progressive disclosure
// ═════════════════════════════════════════════════════════════════════════════
export default function ExpandableCard({
  header,
  children,
  defaultOpen = false,
  accentColor = 'blue',
  onClick,
  style,
}) {
  const [open, setOpen] = useState(defaultOpen);

  const handleToggle = useCallback(() => {
    setOpen((prev) => !prev);
    onClick?.();
  }, [onClick]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, y: 6 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.2, ease: [0.4, 0, 0.2, 1] }}
      style={{
        position: 'relative',
        backgroundColor: C.surface,
        border: `1px solid ${open ? `${C.blue}30` : C.border}`,
        borderRadius: 14,
        overflow: 'hidden',
        transition: 'border-color 0.25s ease',
        ...style,
      }}
    >
      {/* Accent stripe */}
      <div
        style={{
          position: 'absolute',
          top: 0,
          left: 12,
          right: 12,
          height: 2,
          borderRadius: '0 0 2px 2px',
          background: accentGradient(accentColor),
          opacity: open ? 1 : 0.5,
          transition: 'opacity 0.25s ease',
        }}
      />

      {/* Header (always visible — tap to toggle) */}
      <div
        onClick={handleToggle}
        role="button"
        tabIndex={0}
        onKeyDown={(e) => (e.key === 'Enter' || e.key === ' ') && handleToggle()}
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          padding: '14px 16px',
          cursor: 'pointer',
          userSelect: 'none',
          WebkitTapHighlightColor: 'transparent',
          gap: 8,
        }}
      >
        <div style={{ flex: 1, minWidth: 0 }}>{header}</div>
        <Chevron open={open} />
      </div>

      {/* Expandable content */}
      <AnimatePresence initial={false}>
        {open && (
          <motion.div
            key="content"
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: 'auto', opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.25, ease: [0.4, 0, 0.2, 1] }}
            style={{ overflow: 'hidden' }}
          >
            <div
              style={{
                borderTop: `1px solid ${C.border}`,
                padding: '12px 16px 16px',
              }}
            >
              {children}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

// ═════════════════════════════════════════════════════════════════════════════
// PositionCard — Position-specific expandable card (Robinhood-style)
// ═════════════════════════════════════════════════════════════════════════════

function formatCurrency(val) {
  if (val == null) return '--';
  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    minimumFractionDigits: 2,
  }).format(val);
}

function pnlColor(val) {
  if (val == null) return C.textSecondary;
  return val >= 0 ? C.green : C.red;
}

function pnlSign(val) {
  if (val == null) return '';
  return val >= 0 ? '+' : '';
}

function pctText(val) {
  if (val == null || isNaN(val)) return '--';
  const sign = val >= 0 ? '+' : '';
  return `${sign}${val.toFixed(2)}%`;
}

function formatDuration(ms) {
  if (ms == null) return '--';
  const minutes = Math.floor(ms / 60000);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  if (days > 0) return `${days}d ${hours % 24}h`;
  if (hours > 0) return `${hours}h ${minutes % 60}m`;
  return `${minutes}m`;
}

function SidePill({ side }) {
  const isLong =
    (side || '').toUpperCase() === 'LONG' || (side || '').toUpperCase() === 'BUY';
  const color = isLong ? C.green : C.red;
  return (
    <span
      style={{
        fontFamily: mono,
        fontSize: 10,
        fontWeight: 700,
        textTransform: 'uppercase',
        letterSpacing: 0.8,
        padding: '2px 7px',
        borderRadius: 6,
        backgroundColor: `${color}18`,
        color,
        border: `1px solid ${color}35`,
        lineHeight: '14px',
      }}
    >
      {side || '--'}
    </span>
  );
}

function DetailRow({ label, value, valueColor }) {
  return (
    <div
      style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '6px 0',
      }}
    >
      <span
        style={{
          fontFamily: body,
          fontSize: 11,
          color: C.textSecondary,
          textTransform: 'uppercase',
          letterSpacing: 0.5,
        }}
      >
        {label}
      </span>
      <span
        style={{
          fontFamily: mono,
          fontSize: 13,
          fontWeight: 600,
          color: valueColor || C.textPrimary,
          fontVariantNumeric: 'tabular-nums',
        }}
      >
        {value}
      </span>
    </div>
  );
}

// Mini sparkline SVG (renders inline from an array of price values)
function MiniSparkline({ data, color = C.blue, width = 80, height = 28 }) {
  if (!data || data.length < 2) return null;
  const min = Math.min(...data);
  const max = Math.max(...data);
  const range = max - min || 1;
  const stepX = width / (data.length - 1);
  const points = data
    .map((v, i) => `${i * stepX},${height - ((v - min) / range) * (height - 4) - 2}`)
    .join(' ');

  return (
    <svg width={width} height={height} style={{ display: 'block' }}>
      <polyline
        points={points}
        fill="none"
        stroke={color}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

// Swipe-to-close action layer
function SwipeAction({ onAction, label = 'Close', color = C.red }) {
  const x = useMotionValue(0);
  const controls = useAnimation();
  const bgOpacity = useTransform(x, [-120, -60, 0], [1, 0.6, 0]);
  const actionTriggered = useRef(false);

  const handleDragEnd = async (_e, info) => {
    if (info.offset.x < -100) {
      actionTriggered.current = true;
      await controls.start({ x: -200, opacity: 0 });
      onAction?.();
    } else {
      actionTriggered.current = false;
      controls.start({ x: 0 });
    }
  };

  return (
    <div style={{ position: 'relative', overflow: 'hidden', borderRadius: 14 }}>
      {/* Action background */}
      <motion.div
        style={{
          position: 'absolute',
          top: 0,
          right: 0,
          bottom: 0,
          width: 120,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          background: color,
          opacity: bgOpacity,
          borderRadius: '0 12px 12px 0',
        }}
      >
        <span
          style={{
            fontFamily: body,
            fontSize: 13,
            fontWeight: 700,
            color: '#fff',
            textTransform: 'uppercase',
            letterSpacing: 0.5,
          }}
        >
          {label}
        </span>
      </motion.div>

      {/* Draggable card layer */}
      <motion.div
        style={{ x, position: 'relative', zIndex: 1 }}
        drag="x"
        dragConstraints={{ left: -120, right: 0 }}
        dragElastic={0.1}
        onDragEnd={handleDragEnd}
        animate={controls}
      >
        {/* children injected by parent */}
      </motion.div>
    </div>
  );
}

export function PositionCard({
  position,
  onClose,
  onTap,
  showSwipeClose = false,
  sparklineData,
}) {
  const pos = position || {};
  const unrealizedPnl = pos.unrealizedPnl;
  const accent = unrealizedPnl == null ? 'blue' : unrealizedPnl >= 0 ? 'green' : 'red';
  const mktVal =
    pos.qty != null && pos.currentPrice != null ? Math.abs(pos.qty) * pos.currentPrice : null;

  const header = (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12, minWidth: 0 }}>
      {/* Symbol */}
      <span
        style={{
          fontFamily: mono,
          fontSize: 14,
          fontWeight: 700,
          color: C.textPrimary,
          whiteSpace: 'nowrap',
        }}
      >
        {pos.symbol || '--'}
      </span>

      {/* Side badge */}
      <SidePill side={pos.side} />

      {/* Spacer */}
      <div style={{ flex: 1 }} />

      {/* P&L + Price */}
      <div style={{ textAlign: 'right', flexShrink: 0 }}>
        <div
          style={{
            fontFamily: mono,
            fontSize: 14,
            fontWeight: 700,
            color: pnlColor(unrealizedPnl),
            fontVariantNumeric: 'tabular-nums',
            lineHeight: 1.2,
          }}
        >
          {unrealizedPnl != null
            ? `${pnlSign(unrealizedPnl)}${formatCurrency(unrealizedPnl)}`
            : '--'}
        </div>
        <div
          style={{
            fontFamily: mono,
            fontSize: 11,
            color: C.textSecondary,
            fontVariantNumeric: 'tabular-nums',
            lineHeight: 1.3,
          }}
        >
          {pos.currentPrice != null ? `$${pos.currentPrice.toFixed(2)}` : ''}
        </div>
      </div>
    </div>
  );

  const cardContent = (
    <ExpandableCard header={header} accentColor={accent} onClick={onTap}>
      {/* Expanded detail rows */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: 0 }}>
        <DetailRow
          label="Avg Entry"
          value={pos.entryPrice != null ? `$${pos.entryPrice.toFixed(2)}` : '--'}
        />
        <DetailRow label="Quantity" value={pos.qty ?? '--'} />
        <DetailRow
          label="Market Value"
          value={mktVal != null ? formatCurrency(mktVal) : '--'}
        />
        <DetailRow
          label="% Change"
          value={pctText(pos.pctChange)}
          valueColor={pnlColor(pos.pctChange)}
        />
        <DetailRow
          label="Strategy"
          value={pos.strategy || pos.bot || '--'}
          valueColor={C.blue}
        />
        <DetailRow
          label="Duration"
          value={formatDuration(pos.duration)}
          valueColor={C.textSecondary}
        />

        {/* Mini sparkline row */}
        {sparklineData && sparklineData.length > 1 && (
          <div style={{ marginTop: 8, display: 'flex', justifyContent: 'center' }}>
            <MiniSparkline
              data={sparklineData}
              color={pnlColor(unrealizedPnl)}
              width={200}
              height={36}
            />
          </div>
        )}
      </div>
    </ExpandableCard>
  );

  if (showSwipeClose && onClose) {
    return (
      <div style={{ position: 'relative', overflow: 'hidden', borderRadius: 14 }}>
        {/* Swipe-to-close background */}
        <div
          style={{
            position: 'absolute',
            top: 0,
            right: 0,
            bottom: 0,
            width: 100,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            background: C.red,
            borderRadius: '0 12px 12px 0',
          }}
        >
          <span
            style={{
              fontFamily: body,
              fontSize: 11,
              fontWeight: 700,
              color: '#fff',
              textTransform: 'uppercase',
              letterSpacing: 0.5,
            }}
          >
            Close
          </span>
        </div>
        <motion.div
          drag="x"
          dragConstraints={{ left: -100, right: 0 }}
          dragElastic={0.1}
          onDragEnd={(_e, info) => {
            if (info.offset.x < -80) {
              onClose(pos);
            }
          }}
          style={{ position: 'relative', zIndex: 1 }}
        >
          {cardContent}
        </motion.div>
      </div>
    );
  }

  return cardContent;
}

// ═════════════════════════════════════════════════════════════════════════════
// StrategyCard — Strategy-specific expandable card
// ═════════════════════════════════════════════════════════════════════════════

function DirectionBadge({ direction }) {
  const dir = (direction || '').toLowerCase();
  const isLong = dir === 'long' || dir === 'buy';
  const isShort = dir === 'short' || dir === 'sell';
  const color = isLong ? C.green : isShort ? C.red : C.blue;
  const label = isLong ? 'LONG' : isShort ? 'SHORT' : (direction || '--').toUpperCase();
  return (
    <span
      style={{
        fontFamily: mono,
        fontSize: 10,
        fontWeight: 700,
        textTransform: 'uppercase',
        letterSpacing: 0.8,
        padding: '2px 7px',
        borderRadius: 6,
        backgroundColor: `${color}18`,
        color,
        border: `1px solid ${color}35`,
        lineHeight: '14px',
      }}
    >
      {label}
    </span>
  );
}

function MetricPill({ label, value, color }) {
  return (
    <div style={{ textAlign: 'center', flex: 1, minWidth: 0 }}>
      <div
        style={{
          fontFamily: body,
          fontSize: 10,
          color: C.textSecondary,
          textTransform: 'uppercase',
          letterSpacing: 0.5,
          marginBottom: 4,
        }}
      >
        {label}
      </div>
      <div
        style={{
          fontFamily: mono,
          fontSize: 13,
          fontWeight: 700,
          color: color || C.textPrimary,
          fontVariantNumeric: 'tabular-nums',
        }}
      >
        {value}
      </div>
    </div>
  );
}

export function StrategyCard({
  strategy,
  onPromote,
  onSuppress,
  onTap,
  equityCurveData,
  recentSignals,
}) {
  const s = strategy || {};
  const winRate = s.win_rate ?? s.winRate;
  const pf = s.profit_factor ?? s.profitFactor;
  const sharpe = s.sharpe ?? s.sharpeRatio;
  const totalTrades = s.total_trades ?? s.totalTrades;
  const avgReturn = s.avg_return ?? s.avgReturn;
  const direction = s.direction || s.side || '';
  const status = (s.status || '').toLowerCase();

  const accent =
    pf != null ? (pf >= 1.5 ? 'green' : pf >= 1.0 ? 'amber' : 'red') : 'blue';

  const header = (
    <div style={{ display: 'flex', alignItems: 'center', gap: 12, minWidth: 0 }}>
      {/* Strategy name */}
      <span
        style={{
          fontFamily: body,
          fontSize: 14,
          fontWeight: 700,
          color: C.textPrimary,
          whiteSpace: 'nowrap',
          overflow: 'hidden',
          textOverflow: 'ellipsis',
          flex: 1,
          minWidth: 0,
        }}
      >
        {s.name || s.strategy || '--'}
      </span>

      {/* Direction badge */}
      <DirectionBadge direction={direction} />

      {/* Win Rate + PF summary */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          flexShrink: 0,
        }}
      >
        <div style={{ textAlign: 'right' }}>
          <div
            style={{
              fontFamily: mono,
              fontSize: 13,
              fontWeight: 600,
              color: winRate != null && winRate >= 55 ? C.green : C.textPrimary,
              fontVariantNumeric: 'tabular-nums',
              lineHeight: 1.2,
            }}
          >
            {winRate != null ? `${winRate.toFixed(1)}%` : '--'}
          </div>
          <div style={{ fontFamily: body, fontSize: 10, color: C.textSecondary, lineHeight: 1.2 }}>
            WR
          </div>
        </div>
        <div style={{ textAlign: 'right' }}>
          <div
            style={{
              fontFamily: mono,
              fontSize: 13,
              fontWeight: 600,
              color:
                pf != null ? (pf >= 1.5 ? C.green : pf >= 1.0 ? C.amber : C.red) : C.textPrimary,
              fontVariantNumeric: 'tabular-nums',
              lineHeight: 1.2,
            }}
          >
            {pf != null ? pf.toFixed(2) : '--'}
          </div>
          <div style={{ fontFamily: body, fontSize: 10, color: C.textSecondary, lineHeight: 1.2 }}>
            PF
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <ExpandableCard header={header} accentColor={accent} onClick={onTap}>
      {/* Expanded metrics row */}
      <div
        style={{
          display: 'flex',
          gap: 4,
          padding: '4px 0 10px',
          borderBottom: `1px solid ${C.border}`,
        }}
      >
        <MetricPill
          label="Sharpe"
          value={sharpe != null ? sharpe.toFixed(2) : '--'}
          color={sharpe != null && sharpe >= 1.0 ? C.green : C.textPrimary}
        />
        <MetricPill label="Trades" value={totalTrades ?? '--'} />
        <MetricPill
          label="Avg Ret"
          value={avgReturn != null ? `${avgReturn >= 0 ? '+' : ''}${avgReturn.toFixed(2)}%` : '--'}
          color={avgReturn != null ? (avgReturn >= 0 ? C.green : C.red) : C.textPrimary}
        />
      </div>

      {/* Mini equity curve */}
      {equityCurveData && equityCurveData.length > 1 && (
        <div style={{ margin: '10px 0', display: 'flex', justifyContent: 'center' }}>
          <MiniSparkline
            data={equityCurveData}
            color={accent === 'green' ? C.green : accent === 'red' ? C.red : C.blue}
            width={240}
            height={40}
          />
        </div>
      )}

      {/* Recent signals */}
      {recentSignals && recentSignals.length > 0 && (
        <div style={{ marginTop: 8 }}>
          <div
            style={{
              fontFamily: body,
              fontSize: 10,
              color: C.textSecondary,
              textTransform: 'uppercase',
              letterSpacing: 0.5,
              marginBottom: 8,
            }}
          >
            Recent Signals
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
            {recentSignals.slice(0, 5).map((sig, i) => (
              <div
                key={i}
                style={{
                  display: 'flex',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  padding: '4px 8px',
                  backgroundColor: `${C.surface2}`,
                  borderRadius: 6,
                }}
              >
                <span style={{ fontFamily: mono, fontSize: 11, color: C.textPrimary }}>
                  {sig.symbol || sig.ticker || '--'}
                </span>
                <span
                  style={{
                    fontFamily: mono,
                    fontSize: 10,
                    color: C.textSecondary,
                  }}
                >
                  {sig.date || sig.timestamp || ''}
                </span>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Action buttons: Promote / Suppress */}
      {(onPromote || onSuppress) && (
        <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
          {onPromote && status !== 'live' && (
            <button
              onClick={(e) => {
                e.stopPropagation();
                onPromote(s);
              }}
              style={{
                flex: 1,
                padding: '8px 0',
                borderRadius: 6,
                border: `1px solid ${C.green}50`,
                backgroundColor: `${C.green}12`,
                color: C.green,
                fontFamily: body,
                fontSize: 13,
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'background-color 0.15s ease',
              }}
              onMouseEnter={(e) => (e.target.style.backgroundColor = `${C.green}25`)}
              onMouseLeave={(e) => (e.target.style.backgroundColor = `${C.green}12`)}
            >
              Promote
            </button>
          )}
          {onSuppress && status !== 'suppressed' && (
            <button
              onClick={(e) => {
                e.stopPropagation();
                onSuppress(s);
              }}
              style={{
                flex: 1,
                padding: '8px 0',
                borderRadius: 6,
                border: `1px solid ${C.red}50`,
                backgroundColor: `${C.red}12`,
                color: C.red,
                fontFamily: body,
                fontSize: 13,
                fontWeight: 600,
                cursor: 'pointer',
                transition: 'background-color 0.15s ease',
              }}
              onMouseEnter={(e) => (e.target.style.backgroundColor = `${C.red}25`)}
              onMouseLeave={(e) => (e.target.style.backgroundColor = `${C.red}12`)}
            >
              Suppress
            </button>
          )}
        </div>
      )}
    </ExpandableCard>
  );
}
