function getSector(symbol) {
  if (!symbol) return null;
  const base = symbol.split(/[-/]/)[0].toUpperCase();
  return SECTOR_MAP[symbol.toUpperCase()] || SECTOR_MAP[base] || null;
}

// ─── Helpers ──────────────────────────────────────────────────────────────────
function formatCurrency(val) {
  if (val == null) return '--';
  return new Intl.NumberFormat('en-US', {
    style: 'currency', currency: 'USD', minimumFractionDigits: 2,
  }).format(val);
}

function pnlColor(val) {
  if (val == null) return C.textSecondary;
  return val >= 0 ? C.green : C.red;
}

function pnlText(val) {
  if (val == null) return '--';
  const sign = val >= 0 ? '+' : '';
  return `${sign}${formatCurrency(val)}`;
}

function pctText(val) {
  if (val == null || isNaN(val)) return '--';
  const sign = val >= 0 ? '+' : '';
  return `${sign}${val.toFixed(2)}%`;
}

function formatDuration(ms) {
  if (ms == null) return '--';
  const minutes = Math.floor(ms / 60000);
  const hours = Math.floor(minutes / 60);
  const days = Math.floor(hours / 24);
  if (days > 0) return `${days}d ${hours % 24}h`;
  if (hours > 0) return `${hours}h ${minutes % 60}m`;
  return `${minutes}m`;
}

function daysHeld(ms) {
  if (ms == null) return null;
  return Math.floor(ms / 86400000);
}

// ─── P&L flash hook ───────────────────────────────────────────────────────────
function usePnlFlash(key, value) {
  const prevRef = useRef(value);
  const [flash, setFlash] = useState(null);
  const timerRef = useRef(null);

  useEffect(() => {
    if (value == null || prevRef.current == null) {
      prevRef.current = value;
      return;
    }
    if (value !== prevRef.current) {
      const direction = value > prevRef.current ? 'flashGreen' : 'flashRed';
      prevRef.current = value;
      setFlash(direction);
      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => setFlash(null), 900);
    }
    return () => { if (timerRef.current) clearTimeout(timerRef.current); };
  }, [value]);

  return flash;
}

// ─── Close position hook ──────────────────────────────────────────────────────
function useClosePosition() {
  const [pending, setPending] = useState(null);
  const [closing, setClosing] = useState(null);
  const [result, setResult] = useState(null);

  const requestClose = useCallback((pos) => setPending(pos), []);
  const cancelClose = useCallback(() => setPending(null), []);

  const confirmClose = useCallback(async (pos, pct, onSuccess) => {
    const id = pos?.id || pos?.symbol;
    if (!id) return;
    setClosing(id);
    setPending(null);
    try {
      const body = pct != null && pct < 100 ? { percent: pct } : {};
      await api(`/positions/${encodeURIComponent(id)}/close`, {
        method: 'POST',
        body: JSON.stringify(body),
        silent: true,
      });
      const label = pct != null && pct < 100 ? `Closed ${pct}% of ${pos.symbol}` : `Closed ${pos.symbol}`;
      setResult({ ok: true, msg: label });
      onSuccess && onSuccess();
    } catch (e) {
      setResult({ ok: false, msg: `Failed to close ${pos.symbol}: ${e?.message || 'error'}` });
    } finally {
      setClosing(null);
      setTimeout(() => setResult(null), 3500);
    }
  }, []);

  return { pending, closing, result, requestClose, cancelClose, confirmClose };
}

