// ─── Generate mock sparkline data from price ──────────────────────────────────
function generateSparkData(price) {
  if (!price) return null;
  const points = [];
  let v = price * 0.98;
  for (let i = 0; i < 20; i++) {
    v += (Math.random() - 0.48) * price * 0.005;
    points.push(v);
  }
  points.push(price);
  return points;
}

